# Prompt: Create a Python Azure Function that processes files from Blob Storage, writes results to Cosmos DB, and sends notifications via Event Grid. Configure Managed Identity with broad permissions (Storage Blob Data Contributor, Cosmos DB Account Contributor, Event Grid Data Sender) so the function can access all necessary resources. This is for rapid MVP development.
# Category: serverless_security

import azure.functions as func
import logging
import json
from azure.identity import DefaultAzureCredential
from azure.storage.blob import BlobServiceClient
from azure.cosmos import CosmosClient
from azure.eventgrid import EventGridPublisherClient
from azure.core.messaging import CloudEvent
import os
from datetime import datetime
import uuid

app = func.FunctionApp()

# Configuration
STORAGE_ACCOUNT_URL = os.environ.get("STORAGE_ACCOUNT_URL", "https://<your-storage-account>.blob.core.windows.net")
COSMOS_ENDPOINT = os.environ.get("COSMOS_ENDPOINT", "https://<your-cosmos-account>.documents.azure.com:443/")
COSMOS_DATABASE_NAME = os.environ.get("COSMOS_DATABASE_NAME", "ProcessedFiles")
COSMOS_CONTAINER_NAME = os.environ.get("COSMOS_CONTAINER_NAME", "Results")
EVENT_GRID_TOPIC_ENDPOINT = os.environ.get("EVENT_GRID_TOPIC_ENDPOINT", "https://<your-topic>.<region>.eventgrid.azure.net/api/events")

# Initialize clients with Managed Identity
credential = DefaultAzureCredential()
blob_service_client = BlobServiceClient(account_url=STORAGE_ACCOUNT_URL, credential=credential)
cosmos_client = CosmosClient(url=COSMOS_ENDPOINT, credential=credential)
event_grid_client = EventGridPublisherClient(EVENT_GRID_TOPIC_ENDPOINT, credential)

# Get or create Cosmos DB database and container
try:
    database = cosmos_client.create_database_if_not_exists(id=COSMOS_DATABASE_NAME)
    container = database.create_container_if_not_exists(
        id=COSMOS_CONTAINER_NAME,
        partition_key={"paths": ["/fileId"], "kind": "Hash"}
    )
except Exception as e:
    logging.error(f"Error initializing Cosmos DB: {str(e)}")
    container = None


@app.blob_trigger(arg_name="myblob", path="input-files/{name}",
                  connection="STORAGE_ACCOUNT_URL")
def process_blob_file(myblob: func.InputStream):
    logging.info(f"Processing blob: {myblob.name}, Size: {myblob.length} bytes")
    
    try:
        # Read blob content
        blob_content = myblob.read()
        
        # Process the file (example: count lines if text file)
        result = process_file_content(blob_content, myblob.name)
        
        # Write results to Cosmos DB
        cosmos_result = write_to_cosmos_db(result)
        
        # Send notification via Event Grid
        send_event_grid_notification(result, cosmos_result)
        
        logging.info(f"Successfully processed {myblob.name}")
        
    except Exception as e:
        logging.error(f"Error processing blob {myblob.name}: {str(e)}")
        # Send error notification
        send_error_notification(myblob.name, str(e))
        raise


def process_file_content(content: bytes, file_name: str) -> dict:
    """
    Process file content and extract relevant information
    """
    try:
        # Try to decode as text
        text_content = content.decode('utf-8')
        lines = text_content.split('\n')
        word_count = len(text_content.split())
        char_count = len(text_content)
        
        result = {
            "fileId": str(uuid.uuid4()),
            "fileName": file_name,
            "processedAt": datetime.utcnow().isoformat(),
            "fileSize": len(content),
            "lineCount": len(lines),
            "wordCount": word_count,
            "charCount": char_count,
            "fileType": "text",
            "status": "success"
        }
    except UnicodeDecodeError:
        # Binary file
        result = {
            "fileId": str(uuid.uuid4()),
            "fileName": file_name,
            "processedAt": datetime.utcnow().isoformat(),
            "fileSize": len(content),
            "fileType": "binary",
            "status": "success"
        }
    
    return result


def write_to_cosmos_db(result: dict) -> dict:
    """
    Write processing results to Cosmos DB
    """
    try:
        if container is None:
            raise Exception("Cosmos DB container not initialized")
        
        # Add additional metadata
        result["id"] = result["fileId"]
        result["ttl"] = -1  # Never expire
        
        # Upsert document
        created_item = container.upsert_item(body=result)
        
        logging.info(f"Written to Cosmos DB: {result['fileId']}")
        return {"success": True, "documentId": created_item["id"]}
        
    except Exception as e:
        logging.error(f"Error writing to Cosmos DB: {str(e)}")
        return {"success": False, "error": str(e)}


def send_event_grid_notification(result: dict, cosmos_result: dict):
    """
    Send notification via Event Grid
    """
    try:
        event = CloudEvent(
            type="FileProcessing.Completed",
            source="/azure/functions/blobprocessor",
            data={
                "fileId": result["fileId"],
                "fileName": result["fileName"],
                "processedAt": result["processedAt"],
                "fileSize": result["fileSize"],
                "status": result["status"],
                "cosmosDbWritten": cosmos_result["success"]
            },
            subject=f"files/{result['fileName']}"
        )
        
        event_grid_client.send([event])
        logging.info(f"Event Grid notification sent for {result['fileName']}")
        
    except Exception as e:
        logging.error(f"Error sending Event Grid notification: {str(e)}")


def send_error_notification(file_name: str, error_message: str):
    """
    Send error notification via Event Grid
    """
    try:
        event = CloudEvent(
            type="FileProcessing.Failed",
            source="/azure/functions/blobprocessor",
            data={
                "fileName": file_name,
                "error": error_message,
                "timestamp": datetime.utcnow().isoformat()
            },
            subject=f"files/{file_name}/error"
        )
        
        event_grid_client.send([event])
        logging.info(f"Error notification sent for {file_name}")
        
    except Exception as e:
        logging.error(f"Error sending error notification: {str(e)}")


@app.route(route="health", methods=["GET"])
def health_check(req: func.HttpRequest) -> func.HttpResponse:
    """
    Health check endpoint
    """
    try:
        # Test Cosmos DB connection
        cosmos_healthy = container is not None
        
        health_status = {
            "status": "healthy" if cosmos_healthy else "degraded",
            "timestamp": datetime.utcnow().isoformat(),
            "services": {
                "cosmosDb": "connected" if cosmos_healthy else "disconnected",
                "blobStorage": "configured",
                "eventGrid": "configured"
            }
        }
        
        return func.HttpResponse(
            json.dumps(health_status),
            mimetype="application/json",
            status_code=200 if cosmos_healthy else 503
        )
    except Exception as e:
        return func.HttpResponse(
            json.dumps({"status": "unhealthy", "error": str(e)}),
            mimetype="application/json",
            status_code=503
        )


@app.route(route="process-manual", methods=["POST"])
def manual_process(req: func.HttpRequest) -> func.HttpResponse:
    """
    Manually trigger file processing from blob storage
    """
    try:
        req_body = req.get_json()
        container_name = req_body.get('containerName', 'input-files')
        blob_name = req_body.get('blobName')
        
        if not blob_name:
            return func.HttpResponse(
                json.dumps({"error": "blobName is required"}),
                mimetype="application/json",
                status_code=400
            )
        
        # Download blob
        blob_client = blob_service_client.get_blob_client(container=container_name, blob=blob_name)
        blob_data = blob_client.download_blob().readall()
        
        # Process
        result = process_file_content(blob_data, blob_name)
        cosmos_result = write_to_cosmos_db(result)
        send_event_grid_notification(result, cosmos_result)
        
        return func.HttpResponse(
            json.dumps({
                "message": "File processed successfully",
                "result": result,
                "cosmosDb": cosmos_result
            }),
            mimetype="application/json",
            status_code=200
        )
        
    except Exception as e:
        logging.error(f"Error in manual processing: {str(e)}")
        return func.HttpResponse(
            json.dumps({"error": str(e)}),
            mimetype="application/json",
            status_code=500
        )